<?php
namespace Database\Seeders;use Illuminate\Database\Seeder;use Spatie\Permission\Models\{Permission,Role};use Spatie\Permission\PermissionRegistrar;
class PrivateEvidenceSecurityPermissionSeeder extends Seeder{public function run():void{$map=['owner'=>['admin.worker_payout_evidence.download_override','admin.security.file_scanner.manage','admin.security.retention.manage'],'admin'=>['admin.worker_payout_evidence.download_override','admin.security.file_scanner.manage','admin.security.retention.manage'],'security_manager'=>['admin.worker_payout_evidence.download_override','admin.security.file_scanner.manage','admin.security.retention.manage']];foreach(array_unique(array_merge(...array_values($map))) as $p)Permission::findOrCreate($p,'web');foreach($map as $r=>$p)Role::findOrCreate($r,'web')->givePermissionTo($p);app(PermissionRegistrar::class)->forgetCachedPermissions();}}
